Iteratively try inserting each ship into the cheapest feasible assign using a saved-state trial-and-error approach, with fallback to a new empty assign if needed.}
func InsertShips(dispatch Dispatch, oris, dess []Station, total_ship int) Dispatch {
	orderCount := len(oris)
	for j := 0; j < orderCount; j++ {
		bestAssignIdx := -1
		bestCostDelta := 0.0
		ori := oris[j]
		des := dess[j]
		shipID := total_ship + j

		fallbackIdx := dispatch.AssignsLen
		if fallbackIdx >= MAXASSIGNS {
			fallbackIdx = MAXASSIGNS - 1
		}

		for i := 0; i <= dispatch.AssignsLen && i < MAXASSIGNS; i++ {
			if i == dispatch.AssignsLen && i > 0 && dispatch.AssignsLen < MAXASSIGNS {
				continue
			}
			if i < dispatch.AssignsLen && dispatch.Assigns[i].Cost < 0 {
				continue
			}

			oldCost := 0.0
			if i < dispatch.AssignsLen {
				oldCost = dispatch.Assigns[i].Cost
			} else {
				oldCost = 0.0
			}

			savedState := dispatch.Assigns[i]

			ok := dispatch.Assigns[i].AddShip(shipID, ori, des)
			if ok {
				dispatch.Assigns[i].GenRoute()
				newCost := dispatch.Assigns[i].Cost
				costDelta := newCost - oldCost
				if bestAssignIdx == -1 || costDelta < bestCostDelta {
					bestAssignIdx = i
					bestCostDelta = costDelta
				}
				dispatch.Assigns[i] = savedState
				if dispatch.Assigns[i].Cost < 0 {
					dispatch.Assigns[i].GenRoute()
				}
			}
		}

		if bestAssignIdx != -1 {
			targetIdx := bestAssignIdx
			added := dispatch.Assigns[targetIdx].AddShip(shipID, ori, des)
			if added {
				dispatch.Assigns[targetIdx].GenRoute()
				if targetIdx >= dispatch.AssignsLen {
					dispatch.AssignsLen = targetIdx + 1
				}
			} else {
				bestAssignIdx = -1
			}
		}

		if bestAssignIdx == -1 {
			fallbackUsed := false
			for fi := dispatch.AssignsLen; fi < MAXASSIGNS; fi++ {
				if dispatch.Assigns[fi].Cost >= 0 || fi == dispatch.AssignsLen {
					added := dispatch.Assigns[fi].AddShip(shipID, ori, des)
					if added {
						dispatch.Assigns[fi].GenRoute()
