				added := dispatch.Assigns[idx].AddShip(shipID, ori, des)
				if added {
					dispatch.Assigns[idx].GenRoute()
					dispatch.AssignsLen++
				}
			}
		}
	}
	dispatch.RenewnTotalCost()
	return dispatch

