Greedy insertion using a composite score combining incremental distance cost, time window penalty, and load balancing, evaluated across all feasible positions with fallback to a new assign slot.}
func InsertShips(dispatch Dispatch, oris, dess []Station, total_ship int) Dispatch {
	const INF = 1e100
	const DIST_WEIGHT = 1.0
	const TIME_WEIGHT = 0.5
	const LOAD_WEIGHT = 0.3

	for jj := 0; jj < len(oris); jj++ {
		ori := oris[jj]
		des := dess[jj]
		shipID := total_ship + jj

		bestAssignIdx := -1
		bestScore := INF

		for aa := 0; aa < dispatch.AssignsLen && aa < MAXASSIGNS; aa++ {
			assign := &dispatch.Assigns[aa]

			oldCost := assign.Cost
			oldLoad := 0
			for i := 0; i < assign.StationsLen; i++ {
				oldLoad += assign.Stations[i].Load
			}

			ok := assign.AddShip(shipID, ori, des)
			if !ok {
				continue
			}
			assign.GenRoute()
			newCost := assign.Cost
			if newCost < 0 {
				assign.RemoveShip(shipID)
				assign.GenRoute()
				continue
			}

			newLoad := 0
			for i := 0; i < assign.StationsLen; i++ {
				newLoad += assign.Stations[i].Load
			}

			incDistCost := newCost - oldCost
			timePen := 0.0
			if ori.TimeStart > ori.TimeEnd || des.TimeStart > des.TimeEnd {
				timePen = 10000.0
			}
			loadImbalance := float64(newLoad*newLoad) / float64(oldLoad*oldLoad+1)
			score := DIST_WEIGHT*incDistCost + TIME_WEIGHT*timePen + LOAD_WEIGHT*loadImbalance

			if score < bestScore {
				bestScore = score
				bestAssignIdx = aa
			}

			assign.RemoveShip(shipID)
			assign.GenRoute()
		}

		if bestAssignIdx >= 0 {
			target := &dispatch.Assigns[bestAssignIdx]
			target.AddShip(shipID, ori, des)
			target.GenRoute()
		} else {
			if dispatch.AssignsLen < MAXASSIGNS {
				target := &dispatch.Assigns[dispatch.AssignsLen]
				ok := target.AddShip(shipID, ori, des)
				if ok {
					target.GenRoute()
					dispatch.AssignsLen++
				}
			}
		}
	}

	dispatch.RenewnTotalCost()
	return dispatch

