func InsertShips(dispatch Dispatch, oris, dess []Station, total_ship int) Dispatch {
	type candidate struct {
		assignIdx int
		costDelta float64
		feasible   bool
	}
	for shipID := 0; shipID < len(oris); shipID++ {
		id := total_ship + shipID
		ori := oris[shipID]
		des := dess[shipID]
		bestCandidate := candidate{-1, 0, false}
		originalCosts := make([]float64, dispatch.AssignsLen)
		for i := 0; i < dispatch.AssignsLen; i++ {
			originalCosts[i] = dispatch.Assigns[i].Cost
			ok := dispatch.Assigns[i].AddShip(id, ori, des)
			if ok {
				dispatch.Assigns[i].GenRoute()
				if dispatch.Assigns[i].Cost >= 0 {
					delta := dispatch.Assigns[i].Cost - originalCosts[i]
					if !bestCandidate.feasible || delta < bestCandidate.costDelta {
						bestCandidate = candidate{i, delta, true}
					}
				}
				dispatch.Assigns[i].RemoveShip(id)
				dispatch.Assigns[i].GenRoute()
				dispatch.Assigns[i].Cost = originalCosts[i]
			}
		}
		if bestCandidate.feasible {
			dispatch.Assigns[bestCandidate.assignIdx].AddShip(id, ori, des)
			dispatch.Assigns[bestCandidate.assignIdx].GenRoute()
		} else {
			newIdx := dispatch.AssignsLen
			if newIdx < MAXASSIGNS {
				ok := dispatch.Assigns[newIdx].AddShip(id, ori, des)
				if ok {
					dispatch.Assigns[newIdx].GenRoute()
					if dispatch.Assigns[newIdx].Cost >= 0 {
