Iterate over orders, evaluate insertion into each assign via trial-and-error with cost delta tracking, commit best feasible insertion per order, fallback to new empty assign if needed, finally renew total cost.}
func InsertShips(dispatch Dispatch, oris, dess []Station, total_ship int) Dispatch {
	for orderIdx := range oris {
		bestAssignIdx := -1
		bestCostDelta := 1e308
		fallbackAssignIdx := -1

		ori := oris[orderIdx]
		des := dess[orderIdx]
		shipID := total_ship + orderIdx

		existingLen := dispatch.AssignsLen

		for i := 0; i < max(existingLen+1, 1); i++ {
			if i == existingLen && i >= MAXASSIGNS {
				continue
			}

			isNewAssign := i >= existingLen
			currentAssign := &dispatch.Assigns[i]

			if isNewAssign {
				*currentAssign = Assign{}
			}

			oldStateValid := false
			var oldCost float64
			if currentAssign.StationsLen > 0 || isNewAssign {
				if !isNewAssign {
					oldCost = currentAssign.Cost
					oldStateValid = true
				}

				ok := currentAssign.AddShip(shipID, ori, des)
				if ok {
					currentAssign.GenRoute()
					newCost := currentAssign.Cost
					if newCost >= 0 {
						costIncrease := newCost
						if oldStateValid {
							costIncrease = newCost - oldCost
						}

						if costIncrease < bestCostDelta {
							bestCostDelta = costIncrease
							bestAssignIdx = i
						}

						if isNewAssign && fallbackAssignIdx == -1 {
							fallbackAssignIdx = i
						}
					}

					currentAssign.RemoveShip(shipID)
					if oldStateValid {
						currentAssign.GenRoute()
					}
				}
			}
		}

		finalAssignIdx := bestAssignIdx
		if finalAssignIdx == -1 {
			finalAssignIdx = fallbackAssignIdx
		}

		if finalAssignIdx != -1 {
			if finalAssignIdx >= dispatch.AssignsLen {
				dispatch.AssignsLen = finalAssignIdx + 1
			}
			assign := &dispatch.Assigns[finalAssignIdx]
			success := assign.AddShip(shipID, ori, des)
			if success {
				assign.GenRoute()
			}
		}
	}

	dispatch.RenewnTotalCost()
	return dispatch
}

