func InsertShips(dispatch Dispatch, oris, dess []Station, total_ship int) Dispatch {
	const INF = 1e100
	const DIST_WEIGHT = 1.0
	const TIME_WEIGHT = 0.5
	const LOAD_WEIGHT = 0.3

	for jj := 0; jj < len(oris); jj++ {
		ori := oris[jj]
		des := dess[jj]
		shipID := total_ship + jj

		bestAssignIdx := -1
		bestScore := INF

		for aa := 0; aa < dispatch.AssignsLen && aa < MAXASSIGNS; aa++ {
			assign := &dispatch.Assigns[aa]

			oldCost := assign.Cost
			oldLoad := 0
			for i := 0; i < assign.StationsLen; i++ {
				oldLoad += assign.Stations[i].Load
			}

			ok := assign.AddShip(shipID, ori, des)
