Greedy insertion minimizing marginal cost increase plus regret-based tie-breaking considering second-best alternative cost difference.}
func InsertShips(dispatch Dispatch, oris, dess []Station, total_ship int) Dispatch {
	nOrders := len(oris)
	for j := 0; j < nOrders; j++ {
		orderId := total_ship + j
		ori := oris[j]
		des := dess[j]

		type candidate struct {
			assignIdx int
			delta     float64
		}
		var best, secondBest candidate
		best.assignIdx = -1
		best.delta = 1e308
		secondBest.delta = 1e308

		savedCosts := make([]float64, dispatch.AssignsLen)
		for i := 0; i < dispatch.AssignsLen; i++ {
			savedCosts[i] = dispatch.Assigns[i].Cost
		}

		for i := 0; i < dispatch.AssignsLen; i++ {
			ok := dispatch.Assigns[i].AddShip(orderId, ori, des)
			if ok {
				dispatch.Assigns[i].GenRoute()
				delta := dispatch.Assigns[i].Cost - savedCosts[i]
				if delta >= 0 && delta < best.delta {
					secondBest = best
					best.assignIdx = i
					best.delta = delta
				} else if delta >= 0 && delta < secondBest.delta {
					secondBest.assignIdx = i
					secondBest.delta = delta
				}
			}
			dispatch.Assigns[i].RemoveShip(orderId)
			dispatch.Assigns[i].GenRoute()
		}

		scoreThreshold := 0.15
		regretWeight := 0.3
		chosenIdx := -1
		if best.assignIdx >= 0 {
			if secondBest.assignIdx >= 0 {
				regret := secondBest.delta - best.delta
				if regret > 0 && best.delta > 0 {
					score := best.delta*(1-regretWeight) - regret*regretWeight
					if score/best.delta < scoreThreshold {
						chosenIdx = best.assignIdx
					}
				} else {
					chosenIdx = best.assignIdx
				}
			} else {
				chosenIdx = best.assignIdx
			}
		}

		if chosenIdx >= 0 {
			dispatch.Assigns[chosenIdx].AddShip(orderId, ori, des)
			dispatch.Assigns[chosenIdx].GenRoute()
		} else {
			inserted := false
			for i := 0; i < dispatch.AssignsLen && !inserted; i++ {
				ok := dispatch.Assigns[i].AddShip(orderId, ori, des)
				if ok {
					dispatch.Assigns[i].GenRoute()
					inserted = true
				} else {
					dispatch.Assigns[i].RemoveShip(orderId)
				}
			}
			if !inserted && dispatch.AssignsLen < MAXASSIGNS {
				idx := dispatch.AssignsLen
				dispatch.Assigns[idx].AddShip(orderId, ori, des)
				dispatch.Assigns[idx].GenRoute()
				dispatch.AssignsLen++
			}
		}
	}
	dispatch.RenewnTotalCost()
	return dispatch

