		bestAssignIdx := -1
		bestDelta := math.MaxFloat64
		insertSucceeded := false

		for tryAssignIdx := 0; tryAssignIdx <= dispatch.AssignsLen; tryAssignIdx++ {
			if tryAssignIdx >= MAXASSIGNS {
				break
			}
			assignPtr := &dispatch.Assigns[tryAssignIdx]

			oldCost := assignPtr.Cost
			addOk := assignPtr.AddShip(orderId, oris[shipIdx], dess[shipIdx])
			if !addOk {
				continue
			}
			assignPtr.GenRoute()
			newCost := assignPtr.Cost
			if newCost >= 0 {
				delta := newCost - oldCost
				if delta < bestDelta {
					bestDelta = delta
					bestAssignIdx = tryAssignIdx
				}
			}
			assignPtr.RemoveShip(orderId)
			assignPtr.GenRoute()
		}

		if bestAssignIdx != -1 {
			finalAddOk := dispatch.Assigns[bestAssignIdx].AddShip(orderId, oris[shipIdx], dess[shipIdx])
			if finalAddOk {
				dispatch.Assigns[bestAssignIdx].GenRoute()
				if bestAssignIdx >= dispatch.AssignsLen && bestAssignIdx < MAXASSIGNS {
					dispatch.AssignsLen++
				}
				insertSucceeded = true
			}
		}

		if !insertSucceeded {
			fallbackIdx := dispatch.AssignsLen
			if fallbackIdx >= MAXASSIGNS {
				fallbackIdx = MAXASSIGNS - 1
			}
			addOk := dispatch.Assigns[fallbackIdx].AddShip(orderId, oris[shipIdx], dess[shipIdx])
			if addOk {
				dispatch.Assigns[fallbackIdx].GenRoute()
				if fallbackIdx >= dispatch.AssignsLen && fallbackIdx < MAXASSIGNS {
					dispatch.AssignsLen++
				}
			} else {
				for i := 0; i <= dispatch.AssignsLen && i < MAXASSIGNS; i++ {
					dispatch.Assigns[i].RemoveShip(orderId)
				}
				dispatch.Assigns[fallbackIdx].AddShip(orderId, oris[shipIdx], dess[shipIdx])
				dispatch.Assigns[fallbackIdx].GenRoute()
				if fallbackIdx >= dispatch.AssignsLen && fallbackIdx < MAXASSIGNS {
					dispatch.AssignsLen++
				}
			}
		}
	}

	dispatch.RenewnTotalCost()
	return dispatch
}

