			id := total_ship + orderIdx
			savedState := dispatch.Assigns[i]
			if dispatch.Assigns[i].AddShip(id, oris[orderIdx], dess[orderIdx]) {
				dispatch.Assigns[i].GenRoute()
				if dispatch.Assigns[i].Cost >= 0 {
					costDelta := dispatch.Assigns[i].Cost - originalCosts[i]
					if costDelta < bestCostDelta {
						bestCostDelta = costDelta
						bestAssignIdx = i
					}
				}
				dispatch.Assigns[i] = savedState
				dispatch.Assigns[i].GenRoute()
			}
		}
		fallbackUsed := false
		if bestAssignIdx == -1 {
			if dispatch.AssignsLen < MAXASSIGNS {
				bestAssignIdx = dispatch.AssignsLen
				fallbackUsed = true
			} else {
				for i := 0; i < MAXASSIGNS; i++ {
