Regret-3 greedy insertion with weighted distance-time penalty scoring, fallback to first empty slot.}
func InsertShips(dispatch Dispatch, oris, dess []Station, total_ship int) Dispatch {
	for shipID := 0; shipID < len(oris); shipID++ {
		id := total_ship + shipID
		ori := oris[shipID]
		des := dess[shipID]

		type trialResult struct {
			assignIdx int
			score     float64
			ok        bool
			delta     float64
		}
		const topK = 3
		topTrials := make([]trialResult, 0, topK)

		maxTestIdx := dispatch.AssignsLen
		if maxTestIdx < MAXASSIGNS {
			maxTestIdx++
		}

		for i := 0; i < maxTestIdx && i < MAXASSIGNS; i++ {
			var tr trialResult
			tr.assignIdx = i
			tr.ok = false

			saveAssign := dispatch.Assigns[i]
			ok := dispatch.Assigns[i].AddShip(id, ori, des)
			if ok {
				dispatch.Assigns[i].GenRoute()
				newCost := dispatch.Assigns[i].Cost
				if newCost >= 0 {
					delta := newCost - saveAssign.Cost
					tr.delta = delta
					timeWindowPenalty := 0.0
					if ori.TimeEnd != 0 && dess[shipID].TimeEnd != 0 {
						timeSlackOri := float64(ori.TimeEnd - ori.TimeStart)
						timeSlackDes := float64(dess[shipID].TimeEnd - dess[shipID].TimeStart)
						avgSlack := (timeSlackOri + timeSlackDes) / 2.0
						if avgSlack > 0 {
							timeWindowPenalty = 10.0 / (avgSlack + 1.0)
						}
					}
					loadFactor := 1.0
					if saveAssign.StationCurrent.X == 0 && saveAssign.StationCurrent.Y == 0 {
						loadFactor = 0.8
					}
					score := delta*loadFactor + timeWindowPenalty
					tr.score = score
					tr.ok = true
				}
			}
			dispatch.Assigns[i] = saveAssign
			dispatch.Assigns[i].GenRoute()

			if tr.ok {
				inserted := false
				for j := 0; j < len(topTrials); j++ {
					if tr.score < topTrials[j].score {
						topTrials = append(topTrials[:j], append([]trialResult{tr}, topTrials[j:]...)...)
						if len(topTrials) > topK {
							topTrials = topTrials[:topK]
						}
						inserted = true
						break
					}
				}
				if !inserted && len(topTrials) < topK {
					topTrials = append(topTrials, tr)
				}
			}
		}

		inserted := false
		if len(topTrials) > 0 {
			chosenIdx := 0
			if len(topTrials) >= 2 {
				bestScore := topTrials[0].score
				secondBestScore := topTrials[1].score
				regret := secondBestScore - bestScore
				worseThanThird := 0.0
				if len(topTrials) >= 3 {
					worseThanThird = topTrials[2].score - bestScore
				}
				useFirst := true
				if regret < 5.0 && worseThanThird < 15.0 {
					useFirst = false
				}
				if useFirst {
					chosenIdx = 0
				} else {
					minLoadIdx := 0
					minLoad := 1e9
					for k := 0; k < len(topTrials) && k < topK; k++ {
						a := &dispatch.Assigns[topTrials[k].assignIdx]
						approxLoad := a.Cost + topTrials[k].delta
						if approxLoad < minLoad {
							minLoad = approxLoad
							minLoadIdx = k
						}
					}
					chosenIdx = minLoadIdx
				}
			}
			targetAssignIdx := topTrials[chosenIdx].assignIdx
			saveAssign := dispatch.Assigns[targetAssignIdx]
			ok := dispatch.Assigns[targetAssignIdx].AddShip(id, ori, des)
			if ok {
				dispatch.Assigns[targetAssignIdx].GenRoute()
				if dispatch.Assigns[targetAssignIdx].Cost >= 0 {
					inserted = true
				} else {
					dispatch.Assigns[targetAssignIdx] = saveAssign
					dispatch.Assigns[targetAssignIdx].GenRoute()
				}
			} else {
				dispatch.Assigns[targetAssignIdx] = saveAssign
			}
		}

		if !inserted {
			fallbackIdx := -1
			if dispatch.AssignsLen < MAXASSIGNS {
				fallbackIdx = dispatch.AssignsLen
				dispatch.AssignsLen++
			} else {
				for i := 0; i < MAXASSIGNS; i++ {
					emptyCheck := true
					if dispatch.Assigns[i].StationCurrent.X != 0 || dispatch.Assigns[i].StationCurrent.Y != 0 {
						emptyCheck = false
					}
					if emptyCheck && dispatch.Assigns[i].Cost == 0 {
						fallbackIdx = i
						break
					}
				}
			}
			if fallbackIdx >= 0 {
				saveAssign := dispatch.Assigns[fallbackIdx]
				ok := dispatch.Assigns[fallbackIdx].AddShip(id, ori, des)
				if ok {
					dispatch.Assigns[fallbackIdx].GenRoute()
					if dispatch.Assigns[fallbackIdx].Cost >= 0 {
						inserted = true
					} else {
						dispatch.Assigns[fallbackIdx] = saveAssign
						dispatch.Assigns[fallbackIdx].GenRoute()
					}
				} else {
					dispatch.Assigns[fallbackIdx] = saveAssign
				}
				if !inserted && fallbackIdx >= dispatch.AssignsLen-1 {
					dispatch.AssignsLen--
				}
			}
		}
	}
	dispatch.RenewnTotalCost()
	return dispatch

