		ori := oris[shipID]
		des := dess[shipID]

		type trialResult struct {
			assignIdx   int
			costDelta   float64
			insertOk    bool
		}

		bestTwo := [2]trialResult{}
		bestCount := 0

		for i := 0; i < dispatch.AssignsLen+1 && i < MAXASSIGNS; i++ {
			var tr trialResult
			tr.assignIdx = i

			if i == dispatch.AssignsLen {
				dispatch.AssignsLen++
			}

			saveAssign := dispatch.Assigns[i]
			ok := dispatch.Assigns[i].AddShip(id, ori, des)
			if ok {
				dispatch.Assigns[i].GenRoute()
				newCost := dispatch.Assigns[i].Cost
				delta := newCost - saveAssign.Cost
				if newCost >= 0 {
					tr.costDelta = delta
					tr.insertOk = true
				} else {
					ok = false
				}
			}
			if !ok || dispatch.Assigns[i].Cost < 0 {
				dispatch.Assigns[i] = saveAssign
				dispatch.Assigns[i].GenRoute()
				continue
			}

			dispatch.Assigns[i] = saveAssign
			dispatch.Assigns[i].GenRoute()

			if bestCount == 0 {
				bestTwo[0] = tr
				bestCount = 1
			} else if bestCount == 1 {
				if tr.costDelta <= bestTwo[0].costDelta {
					bestTwo[1] = bestTwo[0]
					bestTwo[0] = tr
				} else {
					bestTwo[1] = tr
				}
				bestCount = 2
			} else {
				if tr.costDelta < bestTwo[0].costDelta {
					bestTwo[1] = bestTwo[0]
					bestTwo[0] = tr
				} else if tr.costDelta < bestTwo[1].costDelta {
					bestTwo[1] = tr
				}
			}
		}

		inserted := false
		if bestCount >= 1 {
			idxToUse := bestTwo[0].assignIdx
			if bestCount >= 2 {
				regret := bestTwo[1].costDelta - bestTwo[0].costDelta
				if regret > 0 {
					idxToUse = bestTwo[0].assignIdx
				}
			}
			saveAssign := dispatch.Assigns[idxToUse]
