			if ok {
				dispatch.Assigns[idxToUse].GenRoute()
				if dispatch.Assigns[idxToUse].Cost >= 0 {
					inserted = true
				} else {
					dispatch.Assigns[idxToUse] = saveAssign
					dispatch.Assigns[idxToUse].GenRoute()
				}
			} else {
				dispatch.Assigns[idxToUse] = saveAssign
			}
		}

		if !inserted {
			fallbackIdx := -1
			for i := 0; i < MAXASSIGNS; i++ {
				if i >= dispatch.AssignsLen {
					dispatch.AssignsLen = i + 1
					fallbackIdx = i
					break
				}
